INSERT INTO `v1_858f50fb7dfc8edcc21f599a4e350c037ba5d7de881005f8fe6faf41c79d97b0` VALUES ("様々なミニゲームをご用意してい\nますよ！\nどのミニゲームで遊びますか？", "2020-02-15 15:00:00", 1000001, 13, 0, 1000, 190801, "2030-04-01 14:00:00");
